def bubble_sort(arr, ascending=True):
    n = len(arr)
    for i in range(n):
        for j in range(0, n - 1 - i):
            should_swap = arr[j] > arr[j + 1] if ascending else arr[j] < arr[j + 1]
            if should_swap:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
    return arr
